
import api from '../../Api/api';
import { ApiStandardUser } from '../../Api/config';
import createNotification from 'src/components/Handle.Error/notifications';
const getunavailabilities = async () => {
    try {
        const result = await api.get(ApiStandardUser.api_unavailabilities);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));;
        return null;
    }
};
const addunavailabilities = async (status) => {
    try {
        const result = await api.post(ApiStandardUser.api_unavailabilities, status);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));;
        return null;
    }
};
const updateunavailabilities = async (data) => {
    try {
        const result = await api.put(ApiStandardUser.api_unavailabilities + data.id, data);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));;
        return null;
    }
};



const unavailabilitiesFun = {
    getunavailabilities,
    addunavailabilities,
    updateunavailabilities,
};

export default unavailabilitiesFun;


