import React, { useState, useEffect, useMemo } from 'react';
import {
    CButton,
    CModal,
    CModalHeader,
    CModalTitle,
    CModalBody,
    CModalFooter,
    CForm,
    CCol,
    CFormLabel,
    CFormFeedback,
    CFormInput,
    CFormSelect
} from '@coreui/react';
import CIcon from '@coreui/icons-react';
import { cilPen, cilPlus } from '@coreui/icons';
import { settingsAppointments } from 'src/services/standardUsers/index';
import PropTypes from 'prop-types';
import i18n from 'src/i18n';
import { settingsConfigs } from 'src/services/SupperSettings';

const initialAppointmentState = {
    client_code: '',
    client_name: '',
    client_contact: '',
    date: '',
    time: '',
    duration: '',
    hardware: '',
    software: '',
    meeting_reason: '',
    description: '',
};

const AppointmentsC = ({ refresh, selectedAppointments }) => {
    const [visible, setVisible] = useState(false);
    const [validated, setValidated] = useState(false);
    const [isUpdateMode, setIsUpdateMode] = useState(false);
    const [appointment, setAppointment] = useState(initialAppointmentState);

    useEffect(() => {
        setIsUpdateMode(!!selectedAppointments);
        setAppointment(selectedAppointments || initialAppointmentState);
    }, [selectedAppointments]);

    const handleAddOrUpdate = async () => {
        const result = isUpdateMode
            ? await settingsAppointments.updateAppointments(appointment, `entity/categories/${appointment.id}`)
            : await settingsAppointments.addAppointments(appointment, 'entity/categories');

        if (result) {
            setVisible(false);
            setValidated(false);
            setIsUpdateMode(false);
            setAppointment(initialAppointmentState);
            refresh();
        }
    };

    const handleSubmit = (event) => {
        event.preventDefault();
        const form = event.currentTarget;
        if (!form.checkValidity()) {
            event.stopPropagation();
        }
        setValidated(true);
        if (form.checkValidity()) {
            handleAddOrUpdate();
        }
    };

    const modalTitle = useMemo(() =>
        isUpdateMode ? i18n.t('updateAppointmentTitle') : i18n.t('addAppointmentTitle'),
        [isUpdateMode]
    );

    const handleChange = (field) => (e) => {
        setAppointment({ ...appointment, [field]: e.target.value });
    };
    const [List, setList] = useState([]);

    const fetchCustomers = async () => {
        try {
            const list = await settingsConfigs.getConfig("customers");
            if (list) {
                setList(list?.data);
                setVisible(true)
            }
        } catch (error) {
            console.error('Error fetching admin list:', error);
        }
    };

    return (
        <>
            <CButton color={isUpdateMode ? 'secondary' : 'primary'} onClick={() => fetchCustomers()}>
                <CIcon icon={isUpdateMode ? cilPen : cilPlus} />
            </CButton>

            <CModal alignment="center" visible={visible} onClose={() => setVisible(false)} size="xl">
                <CModalHeader onClose={() => setVisible(false)}>
                    <CModalTitle>{modalTitle}</CModalTitle>
                </CModalHeader>
                <CModalBody>
                    <CForm
                        className="row g-3 needs-validation"
                        noValidate
                        validated={validated}
                        onSubmit={handleSubmit}
                    >
                        {/* Client Info */}
                        <CCol md={12}>
                            <CFormLabel>Select Customer</CFormLabel>
                            <CFormSelect
                                onChange={(e) => {
                                    const selected = List.find(c => c.id === e.target.value);
                                    if (selected) {
                                        setAppointment((prev) => ({
                                            ...prev,
                                            customerId: selected.id,
                                            client_code: selected.code || '',
                                            client_name: selected.username || '',
                                            client_contact: selected.phone_number || '', // adjust keys as per your API response
                                        }));
                                    }
                                }}
                            >
                                <option value="">{i18n.t('selectCustomerPlaceholder')}</option>
                                {List.map((customer) => (
                                    <option key={customer.id} value={customer.id}>
                                        {customer.username} ({customer.code})
                                    </option>
                                ))}
                            </CFormSelect>
                        </CCol>
                        <CCol md={6}>
                            <CFormLabel>Client Code</CFormLabel>
                            <CFormInput value={appointment.client_code} onChange={handleChange('client_code')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>
                        <CCol md={6}>
                            <CFormLabel>Client Name</CFormLabel>
                            <CFormInput value={appointment.client_name} onChange={handleChange('client_name')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>
                        <CCol md={12}>
                            <CFormLabel>Client Contact</CFormLabel>
                            <CFormInput value={appointment.client_contact} onChange={handleChange('client_contact')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>

                        {/* Appointment Info */}
                        <CCol md={6}>
                            <CFormLabel>Date</CFormLabel>
                            <CFormInput type="date" value={appointment.date} onChange={handleChange('date')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>
                        <CCol md={3}>
                            <CFormLabel>Time</CFormLabel>
                            <CFormInput type="time" value={appointment.time} onChange={handleChange('time')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>
                        <CCol md={3}>
                            <CFormLabel>Duration (min)</CFormLabel>
                            <CFormInput type="number" value={appointment.duration} onChange={handleChange('duration')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>

                        {/* Product Info */}
                        <CCol md={6}>
                            <CFormLabel>Hardware</CFormLabel>
                            <CFormInput value={appointment.hardware} onChange={handleChange('hardware')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>
                        <CCol md={6}>
                            <CFormLabel>Software</CFormLabel>
                            <CFormInput value={appointment.software} onChange={handleChange('software')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>
                        <CCol md={12}>
                            <CFormLabel>Meeting Reason</CFormLabel>
                            <CFormInput value={appointment.meeting_reason} onChange={handleChange('meeting_reason')} required />
                            <CFormFeedback invalid>Required</CFormFeedback>
                        </CCol>
                        <CCol md={12}>
                            <CFormLabel>Description</CFormLabel>
                            <CFormInput value={appointment.description} onChange={handleChange('description')} />
                        </CCol>

                        <CModalFooter>
                            <CButton color="secondary" onClick={() => setVisible(false)}>
                                {i18n.t('closeButton')}
                            </CButton>
                            <CButton color="primary" type="submit">
                                {i18n.t('saveButton')}
                            </CButton>
                        </CModalFooter>
                    </CForm>
                </CModalBody>
            </CModal>
        </>
    );
};

AppointmentsC.propTypes = {
    refresh: PropTypes.func.isRequired,
    selectedAppointments: PropTypes.object,
};

export default AppointmentsC;
